var meteor = createSprite(random(50, 350), -20);
meteor.setAnimation("meteor.jpg_1");
var enemy = createSprite(random(50, 350), -20);
enemy.setAnimation("enemyBlack1_1");
enemy.velocityY = 7;
var ship = createSprite(200, 350);
ship.setAnimation("playerShip1_blue_1");
ship.scale = 0.75;
var bullet = createSprite(ship.x, ship.y - 20, 5, 10);
bullet.setAnimation("bullet 2.0.png_1");
bullet.scale = 0.05;
bullet.visible = 0;
var gameState = "play";
var score = 0;
var health = 5;
function updateBackground() {
  background("black");
  if (score >= 20) {
    background("red");
  }
  if (health == 3) {
    background("blue");
  }
}
function handleInput() {
  if (keyDown("left")) {
    ship.x = ship.x - 10;
  }
  if (keyDown("right")) {
    ship.x = ship.x + 10;
  }
  if (keyWentDown("space")) {
    bullet.velocityY = -10;
    bullet.scale = 0.1;
  }
}
function spawnObstacles() {
  if (World.frameCount % 60 === 0) {
    enemy.velocityY = 3;
  }
  if (World.frameCount % 90 === 0) {
    meteor.velocityY = 3;
  }
}
function handleCollisions() {
  if (score >= 150) { gameState = "win"; }
}
function displayUI() {
  fill("white");
  textSize(18);
  text("Score: " + score, 15, 25);
  text("Health: " + health, 15, 50);
}
function showEndScreen(title, subtitle) {
  background("black");
  textAlign(CENTER);
  fill("yellow");
  textSize(40);
  text(title, 200, 180);
  fill(" white");
  textSize(20);
  text(subtitle, 200, 220);
  text("Final Score: " + score, 200, 260);
}
function draw() {
  handleCollisions();
  updateBackground();
  fill("white");
  textSize(12);
  text("Left and right to move,space to shoot.", 105, 200);
  if (enemy.y == 600) {
    enemy.y = 0;
  }
  if (meteor.y == 600) {
    meteor.y = 0;
  }
  if (enemy.isTouching(ship)) {
      health = health - 1;
    }
  if (bullet.isTouching(enemy)) {
   score = score + 1;
  bullet.visible = 0;
  bullet.velocityY = 0;
  enemy.x = randomNumber(1, 400);
  enemy.y = 0;
}
  if (bullet.isTouching(meteor)) {
      meteor.x = randomNumber(1, 400);
      meteor.y = 0;
      bullet.visible = 0;
      bullet.velocityY = 0;
      score = score + 1;
      bullet.y = ship.y;
      bullet.x = ship.x;
    }
  if (health == 0) {
      gameState = "over";
    }
  if (enemy.isTouching(ship)) {
      enemy.x = randomNumber(1, 400);
      enemy.y = 0;
    }
  if (meteor.isTouching(ship)) {
      meteor.x = randomNumber(1, 400);
      meteor.y = 0;
      health = health - 1;
    }
  if (keyWentDown("space") && bullet.visible == 0) {
      bullet.x = ship.x;
      bullet.y = ship.y - 45;
      bullet.visible = 1;
      bullet.velocityY = -10;
    }
  if (bullet.y < 0) {
      bullet.visible = 0;
      bullet.velocityY = 0;
    }
  if (gameState === "play") {
      handleInput();
      spawnObstacles();
      handleCollisions(); 
      drawSprites();
      displayUI();
    } else if (gameState === "win") {
      showEndScreen("YOU WIN!", "The galaxy is safe.");
    } else if (gameState === "over") {
      showEndScreen("GAME OVER", "Try again, pilot.");
    }
  if (bullet.isTouching(enemy)) {
    enemy.x = randomNumber(1, 400);
enemy.y = 0;
    }
  if (enemy.y >= 400) {
    enemy.y = 0;
    health = health - 1;
  }
  if (meteor.y >= 400) {
    meteor.y = 0;
    health = health - 1;
  }
  }
